  1→import React from 'react';
  2→import {ActivityIndicator, StyleSheet, Text, View} from 'react-native';
  3→import {NavigationContainer, DarkTheme} from '@react-navigation/native';
  4→import {createBottomTabNavigator} from '@react-navigation/bottom-tabs';
