 11→import {ExploreScreen} from '../screens/Home/ExploreScreen';
 12→import {NotificationsScreen} from '../screens/Notifications/NotificationsScreen';
 13→import {ProfileScreen} from '../screens/Profile/ProfileScreen';
 14→import {PostDetailScreen} from '../screens/Home/PostDetailScreen';
 15→import {JournalEditorScreen} from '../screens/Editor/JournalEditorScreen';
 16→import {CanvasScreen} from '../screens/Advanced/CanvasScreen';
 17→import {FreedomWallScreen} from '../screens/Advanced/FreedomWallScreen';
 18→import {UniverseScreen} from '../screens/Advanced/UniverseScreen';
