 27→import type {
 28→  AuthStackParamList,
 29→  MainTabParamList,
 30→  RootStackParamList,
 31→} from './types';
 32→
 33→const RootStack = createNativeStackNavigator<RootStackParamList>();
 34→const AuthStack = createNativeStackNavigator<AuthStackParamList>();
 35→const MainTabs = createBottomTabNavigator<MainTabParamList>();
 36→
 37→const navTheme = {
 38→  ...DarkTheme,
 39→  colors: {
 40→    ...DarkTheme.colors,
 41→    background: colors.background,
 42→    card: colors.surface,
 43→    border: colors.border,
 44→    text: colors.text,
 45→    primary: colors.accent,
 46→  },
 47→};
 48→
 49→function AuthNavigator() {
 50→  return (
 51→    <AuthStack.Navigator
 52→      screenOptions={{
 53→        headerStyle: {backgroundColor: colors.surface},
 54→        headerTintColor: colors.text,
 55→      }}>
 56→      <AuthStack.Screen
 57→        name="Login"
 58→        component={LoginScreen}
 59→        options={{title: 'Login'}}
 60→      />
 61→      <AuthStack.Screen
 62→        name="SignUp"
 63→        component={SignUpScreen}
 64→        options={{title: 'Sign Up'}}
 65→      />
 66→    </AuthStack.Navigator>
 67→  );
 68→}
 69→
 70→function MainTabNavigator() {
 71→  return (
 72→    <MainTabs.Navigator
 73→      screenOptions={{
 74→        headerStyle: {backgroundColor: colors.surface},
 75→        headerTintColor: colors.text,
 76→        tabBarStyle: {
 77→          backgroundColor: colors.surface,
 78→          borderTopColor: colors.border,
 79→        },
 80→        tabBarActiveTintColor: colors.accent,
 81→        tabBarInactiveTintColor: colors.textMuted,
 82→      }}>
 83→      <MainTabs.Screen name="Home" component={HomeFeedScreen} />
 84→      <MainTabs.Screen name="Explore" component={ExploreScreen} />
 85→      <MainTabs.Screen name="Stories" component={StoryBrowserScreen} />
