 95→export function RootNavigator() {
 96→  const {loading, session} = useAuth();
 97→
 98→  if (loading) {
 99→    return (
100→      <View style={styles.loadingContainer}>
101→        <ActivityIndicator color={colors.accent} />
102→        <Text style={styles.loadingText}>Loading session...</Text>
103→      </View>
104→    );
105→  }
106→
107→  return (
108→    <NavigationContainer theme={navTheme}>
109→      <RootStack.Navigator
110→        screenOptions={{
111→          headerStyle: {backgroundColor: colors.surface},
112→          headerTintColor: colors.text,
113→          contentStyle: {backgroundColor: colors.background},
114→        }}>
115→        {!session ? (
116→          <RootStack.Screen
117→            name="Auth"
118→            component={AuthNavigator}
119→            options={{headerShown: false}}
120→          />
121→        ) : (
122→          <>
123→            <RootStack.Screen
124→              name="Main"
125→              component={MainTabNavigator}
126→              options={{headerShown: false}}
127→            />
128→            <RootStack.Screen
129→              name="PostDetail"
130→              component={PostDetailScreen}
131→              options={{title: 'Post'}}
132→            />
133→            <RootStack.Screen
134→              name="JournalEditor"
135→              component={JournalEditorScreen}
136→              options={{title: 'Journal Editor'}}
137→            />
