280→        format: '',
281→        indent: 0,
282→        type: 'root',
283→        version: 1,
284→      },
285→    };
286→
287→    formData.append('title', payload.title);
288→    formData.append('content', JSON.stringify(lexicalPayload));
289→    formData.append('post_type', 'text');
290→
291→    return apiRequest<{ message?: string }>('/save-journal', {
292→      method: 'POST',
293→      headers: {
294→        ...authHeaders(token),
295→      },
296→      body: formData,
297→      timeoutMs: 30000,
298→      retries: 0,
299→    });
300→  },
301→};
