  8→.auth-shell {
  9→    display: grid;
 10→    grid-template-columns: 1fr 1fr;
 11→    min-height: 100svh;
 12→    background-color: var(--bg-primary);
 13→    color: var(--text-primary);
 14→    font-family: var(--font-ui);
 15→    overflow-x: hidden;
 16→}
 17→
 18→/* ── Left Panel: Brand Story ── */
 19→.auth-panel {
 20→    position: relative;
 21→    display: flex;
 22→    flex-direction: column;
 23→    justify-content: center;
 24→    padding: 64px 72px;
 25→    background: var(--bg-card);
 26→    border-right: 1px solid var(--border-card);
 27→    overflow: hidden;
 28→}
 29→
 30→/* Decorative ink blot shapes */
 31→.auth-panel::before {
 32→    content: '';
 33→    position: absolute;
 34→    width: 400px;
 35→    height: 400px;
 36→    border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%;
 37→    background: radial-gradient(
 38→        ellipse at 30% 30%,
 39→        rgba(212, 168, 83, 0.08),
 40→        transparent 70%
 41→    );
 42→    top: -120px;
 43→    left: -100px;
 44→    animation: morph 20s ease-in-out infinite;
 45→}
 46→
 47→.auth-panel::after {
 48→    content: '';
 49→    position: absolute;
 50→    width: 300px;
 51→    height: 300px;
 52→    border-radius: 61% 39% 47% 53% / 49% 55% 45% 51%;
 53→    background: radial-gradient(
 54→        ellipse at 70% 60%,
 55→        rgba(212, 168, 83, 0.06),
 56→        transparent 70%
 57→    );
 58→    bottom: -80px;
 59→    right: 20px;
 60→    animation: morph 25s ease-in-out infinite reverse;
 61→}
 62→
 63→@keyframes morph {
 64→    0%, 100% { border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%; }
 65→    25% { border-radius: 55% 45% 50% 50% / 60% 40% 60% 40%; }
 66→    50% { border-radius: 40% 60% 55% 45% / 50% 55% 45% 50%; }
 67→    75% { border-radius: 60% 40% 45% 55% / 45% 60% 40% 55%; }
 68→}
