  1→import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
  2→import type { AuthChangeEvent, Session, User } from '@supabase/auth-js';
  3→import { IS_SUPABASE_CONFIGURED } from '../../config/env';
  4→import * as supabaseModule from '../../lib/supabase';
  5→
  6→type Credentials = {
  7→  email: string;
  8→  password: string;
  9→};
 10→
 11→type AuthContextValue = {
 12→  user: User | null;
 13→  session: Session | null;
 14→  loading: boolean;
 15→  authError: string | null;
 16→  signIn: (credentials: Credentials) => Promise<void>;
 17→  signUp: (credentials: Credentials) => Promise<void>;
 18→  signOut: () => Promise<void>;
 19→};
 20→
 21→const AuthContext = createContext<AuthContextValue | undefined>(undefined);
 22→
 23→const notConfiguredMessage =
 24→  'Supabase is not configured. Set ISK_MOBILE_SUPABASE_URL and ISK_MOBILE_SUPABASE_ANON_KEY before using auth flows.';
 25→const unavailableClientMessage =
 26→  'Supabase client is unavailable. Restart Metro with --reset-cache and relaunch the app.';
 27→
 28→const supabase = supabaseModule?.supabase;
 29→
 30→const resolveAuthClient = () => {
 31→  if (!IS_SUPABASE_CONFIGURED) {
 32→    throw new Error(notConfiguredMessage);
 33→  }
 34→  if (!supabase) {
 35→    throw new Error(unavailableClientMessage);
 36→  }
 37→
 38→  return supabase.auth;
 39→};
 40→
 41→export function AuthProvider({ children }: { children: React.ReactNode }) {
 42→  const [session, setSession] = useState<Session | null>(null);
 43→  const [loading, setLoading] = useState(true);
 44→  const [authError, setAuthError] = useState<string | null>(null);
 45→
 46→  useEffect(() => {
 47→    let mounted = true;
 48→
 49→    if (!IS_SUPABASE_CONFIGURED) {
 50→      setAuthError(notConfiguredMessage);
 51→      setLoading(false);
 52→      return () => {
 53→        mounted = false;
 54→      };
 55→    }
 56→
 57→    if (!supabase) {
 58→      setAuthError(unavailableClientMessage);
 59→      setLoading(false);
 60→      return () => {
 61→        mounted = false;
 62→      };
 63→    }
 64→
 65→    setAuthError(null);
 66→
 67→    (async () => {
 68→      try {
 69→        const { data, error } = await supabase.auth.getSession();
 70→        if (!mounted) {
 71→          return;
 72→        }
 73→
 74→        if (error) {
 75→          setAuthError(error.message);
 76→        } else {
 77→          setAuthError(null);
 78→        }
 79→
 80→        setSession(data.session ?? null);
 81→      } catch (error) {
 82→        if (!mounted) {
 83→          return;
 84→        }
 85→
 86→        setAuthError(error instanceof Error ? error.message : 'Failed to load auth session.');
 87→      } finally {
 88→        if (mounted) {
 89→          setLoading(false);
 90→        }
 91→      }
 92→    })();
 93→
 94→    const {
 95→      data: { subscription },
 96→    } = supabase.auth.onAuthStateChange((_event: AuthChangeEvent, nextSession: Session | null) => {
 97→      setSession(nextSession);
 98→      setAuthError(null);
 99→    });
100→
101→    return () => {
102→      mounted = false;
103→      subscription.unsubscribe();
104→    };
105→  }, []);
106→
107→  const value = useMemo<AuthContextValue>(
108→    () => ({
109→      user: session?.user ?? null,
110→      session,
111→      loading,
112→      authError,
113→      signIn: async ({ email, password }) => {
114→        const auth = resolveAuthClient();
115→        setAuthError(null);
116→
117→        try {
118→          const { error } = await auth.signInWithPassword({ email, password });
119→          if (error) {
120→            throw error;
121→          }
122→        } catch (error) {
123→          const message = error instanceof Error ? error.message : 'Sign in failed.';
124→          setAuthError(message);
125→          throw error;
126→        }
127→      },
128→      signUp: async ({ email, password }) => {
129→        const auth = resolveAuthClient();
130→        setAuthError(null);
131→
132→        try {
133→          const { error } = await auth.signUp({ email, password });
134→          if (error) {
135→            throw error;
136→          }
137→        } catch (error) {
138→          const message = error instanceof Error ? error.message : 'Sign up failed.';
139→          setAuthError(message);
140→          throw error;
141→        }
142→      },
143→      signOut: async () => {
144→        const auth = resolveAuthClient();
145→        setAuthError(null);
146→
147→        try {
148→          const { error } = await auth.signOut();
149→          if (error) {
150→            throw error;
151→          }
152→        } catch (error) {
153→          const message = error instanceof Error ? error.message : 'Sign out failed.';
154→          setAuthError(message);
155→          throw error;
156→        }
157→      },
158→    }),
159→    [authError, loading, session],
160→  );
161→
162→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
163→}
164→
165→export function useAuth() {
166→  const context = useContext(AuthContext);
167→  if (!context) {
168→    throw new Error('useAuth must be used within AuthProvider');
169→  }
170→
171→  return context;
172→}
173→

  1→import {
  2→  ISK_MOBILE_API_BASE_URL,
  3→  ISK_MOBILE_SUPABASE_ANON_KEY,
  4→  ISK_MOBILE_SUPABASE_URL,
  5→} from '@env';
  6→
  7→export type MobileEnv = {
  8→  API_BASE_URL: string;
  9→  SUPABASE_URL: string;
 10→  SUPABASE_ANON_KEY: string;
 11→};
 12→
 13→export type RawMobileEnv = {
 14→  ISK_MOBILE_API_BASE_URL?: string;
 15→  ISK_MOBILE_SUPABASE_URL?: string;
 16→  ISK_MOBILE_SUPABASE_ANON_KEY?: string;
 17→};
 18→
 19→export type MobileEnvBuildResult = {
 20→  env: MobileEnv;
 21→  warnings: string[];
 22→  isSupabaseConfigured: boolean;
 23→};
 24→
 25→const DEFAULT_API_BASE_URL = 'http://10.0.2.2:3000/api';
 26→const PLACEHOLDER_VALUE_FRAGMENTS = [
 27→  'your-project-ref',
 28→  'your-supabase-anon-key',
 29→  'public-anon-key-placeholder',
 30→  'example.supabase.co',
 31→];
 32→
 33→const fromEnv = (value: string | undefined): string => String(value ?? '').trim();
 34→
 35→const stripTrailingSlashes = (value: string): string => value.replace(/\/+$/, '');
 36→
 37→const isLikelyHttpUrl = (value: string): boolean => {
 38→  if (!value) {
 39→    return false;
 40→  }
 41→
 42→  try {
 43→    const parsed = new URL(value);
 44→    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
 45→  } catch {
 46→    return false;
 47→  }
 48→};
 49→
 50→const isPlaceholderValue = (value: string): boolean => {
 51→  const normalized = value.toLowerCase();
 52→  return PLACEHOLDER_VALUE_FRAGMENTS.some((fragment) => normalized.includes(fragment));
 53→};
 54→
 55→const normalizeApiBaseUrl = (rawValue: string, warnings: string[]): string => {
 56→  const value = rawValue.trim();
 57→  if (!value) {
 58→    warnings.push(
 59→      'ISK_MOBILE_API_BASE_URL is unset; falling back to http://10.0.2.2:3000/api for emulator development.',
 60→    );
 61→    return DEFAULT_API_BASE_URL;
 62→  }
 63→
 64→  const normalized = stripTrailingSlashes(value);
 65→  if (!isLikelyHttpUrl(normalized)) {
 66→    warnings.push(
 67→      `ISK_MOBILE_API_BASE_URL is invalid ("${value}"); falling back to ${DEFAULT_API_BASE_URL}.`,
 68→    );
 69→    return DEFAULT_API_BASE_URL;
 70→  }
 71→
 72→  return normalized;
 73→};
 74→
 75→const normalizeSupabaseUrl = (rawValue: string, warnings: string[]): string => {
 76→  const value = stripTrailingSlashes(rawValue.trim());
 77→  if (!value) {
 78→    return '';
 79→  }
 80→
 81→  if (isPlaceholderValue(value)) {
 82→    warnings.push('ISK_MOBILE_SUPABASE_URL contains a template placeholder value.');
 83→    return '';
 84→  }
 85→
 86→  if (!isLikelyHttpUrl(value)) {
 87→    warnings.push(`ISK_MOBILE_SUPABASE_URL is not a valid http(s) URL ("${rawValue}").`);
 88→    return '';
 89→  }
 90→
 91→  return value;
 92→};
 93→
 94→const normalizeSupabaseAnonKey = (rawValue: string, warnings: string[]): string => {
 95→  const value = rawValue.trim();
 96→  if (!value) {
 97→    return '';
 98→  }
 99→
100→  if (isPlaceholderValue(value)) {
101→    warnings.push('ISK_MOBILE_SUPABASE_ANON_KEY contains a template placeholder value.');
102→    return '';
103→  }
104→
105→  return value;
106→};
107→
108→export const buildMobileEnv = (rawEnv: RawMobileEnv): MobileEnvBuildResult => {
109→  const warnings: string[] = [];
110→
111→  const env: MobileEnv = {
112→    API_BASE_URL: normalizeApiBaseUrl(fromEnv(rawEnv.ISK_MOBILE_API_BASE_URL), warnings),
113→    SUPABASE_URL: normalizeSupabaseUrl(fromEnv(rawEnv.ISK_MOBILE_SUPABASE_URL), warnings),
114→    SUPABASE_ANON_KEY: normalizeSupabaseAnonKey(
115→      fromEnv(rawEnv.ISK_MOBILE_SUPABASE_ANON_KEY),
116→      warnings,
117→    ),
118→  };
119→
120→  return {
121→    env,
122→    warnings,
123→    isSupabaseConfigured: env.SUPABASE_URL.length > 0 && env.SUPABASE_ANON_KEY.length > 0,
124→  };
125→};
126→
127→const resolvedMobileEnv = buildMobileEnv({
128→  ISK_MOBILE_API_BASE_URL,
129→  ISK_MOBILE_SUPABASE_URL,
130→  ISK_MOBILE_SUPABASE_ANON_KEY,
131→});
132→
133→export const MOBILE_ENV: MobileEnv = resolvedMobileEnv.env;
134→export const IS_SUPABASE_CONFIGURED = resolvedMobileEnv.isSupabaseConfigured;
135→export const ENV_WARNINGS = Object.freeze([...resolvedMobileEnv.warnings]);
136→
137→if (__DEV__ && ENV_WARNINGS.length > 0) {
138→  for (const warning of ENV_WARNINGS) {
139→    // Surface non-fatal configuration issues during local development.
140→    console.warn(`[env] ${warning}`);
141→  }
142→}
143→

 1→import AsyncStorage from '@react-native-async-storage/async-storage';
 2→import { AuthClient } from '@supabase/auth-js';
 3→import { IS_SUPABASE_CONFIGURED, MOBILE_ENV } from '../config/env';
 4→
 5→const stripTrailingSlashes = (value: string): string => value.replace(/\/+$/, '');
 6→
 7→const extractProjectRef = (supabaseUrl: string): string => {
 8→  const match = supabaseUrl.match(/^https?:\/\/([^./]+)\./i);
 9→  return match?.[1] ?? 'mobile';
10→};
11→
12→type SupabaseClient = {
13→  auth: InstanceType<typeof AuthClient>;
14→};
15→
16→const createSupabaseClient = (): SupabaseClient => {
17→  const resolvedSupabaseUrl = stripTrailingSlashes(MOBILE_ENV.SUPABASE_URL);
18→  const resolvedSupabaseKey = MOBILE_ENV.SUPABASE_ANON_KEY;
19→  const authUrl = `${resolvedSupabaseUrl}/auth/v1`;
20→  const storageKey = `sb-${extractProjectRef(resolvedSupabaseUrl)}-auth-token`;
21→
22→  const auth = new AuthClient({
23→    url: authUrl,
24→    headers: {
25→      Authorization: `Bearer ${resolvedSupabaseKey}`,
26→      apikey: resolvedSupabaseKey,
27→      'X-Client-Platform': 'react-native',
28→    },
29→    storageKey,
30→    autoRefreshToken: true,
31→    persistSession: true,
32→    detectSessionInUrl: false,
33→    storage: AsyncStorage,
34→    hasCustomAuthorizationHeader: true,
35→  });
36→
37→  return { auth };
38→};
39→
40→export const supabase: SupabaseClient | null = IS_SUPABASE_CONFIGURED
41→  ? createSupabaseClient()
42→  : null;
