  5→type AppErrorBoundaryProps = {
  6→  children: React.ReactNode;
  7→};
  8→
  9→type AppErrorBoundaryState = {
 10→  hasError: boolean;
 11→  errorMessage: string | null;
 12→};
 13→
 14→export class AppErrorBoundary extends React.Component<
 15→  AppErrorBoundaryProps,
 16→  AppErrorBoundaryState
 17→> {
 18→  state: AppErrorBoundaryState = {
 19→    hasError: false,
 20→    errorMessage: null,
 21→  };
 22→
 23→  static getDerivedStateFromError(error: Error): AppErrorBoundaryState {
 24→    return {
 25→      hasError: true,
 26→      errorMessage: error.message || 'Unexpected error',
 27→    };
 28→  }
 29→
 30→  componentDidCatch(error: Error): void {
 31→    // Keep crash context visible in development while showing a user-safe fallback.
 32→    console.error('[AppErrorBoundary] Unhandled runtime error', error);
 33→  }
 34→
 35→  private onRetry = () => {
 36→    this.setState({
 37→      hasError: false,
 38→      errorMessage: null,
 39→    });
 40→  };
 41→
 42→  render(): React.ReactNode {
 43→    if (!this.state.hasError) {
 44→      return this.props.children;
 45→    }
 46→
 47→    return (
 48→      <View style={styles.container}>
 49→        <Text style={styles.title}>Something went wrong</Text>
 50→        <Text style={styles.body}>
 51→          The app hit an unexpected runtime error. Try again or restart the app.
 52→        </Text>
 53→        {!!this.state.errorMessage && __DEV__ && (
 54→          <Text style={styles.errorText}>{this.state.errorMessage}</Text>
 55→        )}
 56→        <Pressable onPress={this.onRetry} style={({ pressed }) => [styles.button, pressed && styles.buttonPressed]}>
 57→          <Text style={styles.buttonText}>Try again</Text>
 58→        </Pressable>
 59→      </View>
 60→    );
 61→  }
 62→}
