 32→      <TextInput
 33→        placeholder="Search users or journals"
 34→        placeholderTextColor={colors.textMuted}
 35→        value={query}
 36→        onChangeText={setQuery}
 37→        style={styles.input}
 38→        autoCapitalize="none"
 39→      />
 40→      <PrimaryButton
 41→        label="Search"
 42→        onPress={() => usersQuery.refetch()}
 43→        kind="secondary"
 44→      />
 45→
 46→      {normalizedQuery.length < 2 ? (
 47→        <Text style={styles.hint}>Type at least 2 characters.</Text>
 48→      ) : (
 49→        <View style={styles.results}>
 50→          <View style={styles.card}>
 51→            <Text style={styles.sectionTitle}>Users</Text>
 52→            {usersQuery.data?.data?.length ? (
 53→              usersQuery.data.data.map(user => (
 54→                <Text key={user.id} style={styles.item}>
 55→                  {`- ${user.name || user.username || user.id}`}
 56→                </Text>
 57→              ))
 58→            ) : (
 59→              <Text style={styles.hint}>No users found.</Text>
 60→            )}
 61→          </View>
 62→
