 16→const stripHtml = (html: string): string => {
 17→  return html
 18→    .replace(/<[^>]*>/g, ' ')
 19→    .replace(/&nbsp;/g, ' ')
 20→    .replace(/\s+/g, ' ')
 21→    .trim();
 22→};
