137→                navigation.navigate('StoryChapterReader', {
138→                  storyId,
139→                  chapterId: chapter.id,
140→                })
141→              }
142→              style={({pressed}) => [styles.chapterItem, pressed && styles.chapterPressed]}>
143→              <Text style={styles.chapterTitle}>
144→                {`Ch. ${chapter.chapter_number || '?'}: ${chapter.title}`}
145→              </Text>
146→              <Text style={styles.chapterMeta}>
147→                {(chapter.status || 'draft').toString()}
148→                {` • ${(chapter.word_count || 0).toLocaleString()} words`}
149→              </Text>
150→            </Pressable>
151→          ))
152→        )}
153→      </View>
154→    </Screen>
155→  );
