 67→  const createMutation = useMutation({
 68→    mutationFn: () =>
 69→      storyApi.createStory(token, {
 70→        title,
 71→        description,
 72→        status,
 73→        privacy,
 74→        tags,
 75→      }),
 76→    onSuccess: data => {
 77→      queryClient.invalidateQueries({queryKey: ['stories-dashboard']});
 78→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
 79→      navigation.replace('StoryChapterManager', {storyId: data.id});
 80→    },
 81→    onError: error => {
 82→      Alert.alert(
 83→        'Failed to create story',
 84→        error instanceof Error ? error.message : 'Unknown error',
 85→      );
 86→    },
 87→  });
 88→
 89→  const updateMutation = useMutation({
 90→    mutationFn: () =>
 91→      storyApi.updateStory(token, storyId ?? '', {
 92→        title,
 93→        description,
 94→        status,
 95→        privacy,
 96→        tags,
 97→      }),
 98→    onSuccess: data => {
 99→      queryClient.invalidateQueries({queryKey: ['story', data.id]});
100→      queryClient.invalidateQueries({queryKey: ['stories-dashboard']});
101→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
102→      navigation.replace('StoryChapterManager', {storyId: data.id});
103→    },
104→    onError: error => {
105→      Alert.alert(
106→        'Failed to update story',
