140→    } else {
141→      createMutation.mutate();
142→    }
143→  };
144→
145→  return (
146→    <Screen scroll={false}>
147→      <ScrollView contentContainerStyle={styles.content}>
148→        <Text style={styles.title}>{isEdit ? 'Edit Story' : 'New Story'}</Text>
