 42→      ),
 43→    onSuccess: data => {
 44→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 45→      setNewChapterTitle('');
 46→      navigation.navigate('StoryChapterEditor', {storyId, chapterId: data.id});
 47→    },
 48→    onError: error => {
