    fontFamily: fonts.ui.regular,
    fontSize: 15,
    lineHeight: 22,
  } as TextStyle,

  uiMedium: {
    fontFamily: fonts.ui.medium,
    fontSize: 15,
    lineHeight: 22,
  } as TextStyle,

  // Captions and small text (Outfit)
  caption: {
    fontFamily: fonts.ui.regular,
    fontSize: 12,
    lineHeight: 16,
    letterSpacing: 0.2,
  } as TextStyle,

  // Labels (Outfit uppercase)
  label: {
    fontFamily: fonts.ui.semiBold,
    fontSize: 11,
    lineHeight: 14,
    letterSpacing: 1,
    textTransform: 'uppercase',
  } as TextStyle,

  // Buttons (Outfit)
  button: {
    fontFamily: fonts.ui.semiBold,
    fontSize: 15,
    lineHeight: 20,
    letterSpacing: 0.3,
  } as TextStyle,

  buttonSmall: {
    fontFamily: fonts.ui.medium,
    fontSize: 13,
    lineHeight: 18,
    letterSpacing: 0.2,
  } as TextStyle,

  // Tab bar labels
  tabLabel: {
    fontFamily: fonts.ui.semiBold,
    fontSize: 11,
    lineHeight: 14,
  } as TextStyle,
} as const;

