  },
  brandSection: {
    alignItems: 'center',
    marginBottom: spacing.xxl,
  },
  brandText: {
    fontFamily: fonts.heading.bold,
    fontSize: 28,
    letterSpacing: -0.3,
  },
  tagline: {
    fontFamily: fonts.serif.italic,
    fontSize: 15,
