 85→    queryKey: ['feed', user?.id],
 86→    queryFn: ({pageParam}) => mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 87→    initialPageParam: null as string | null,
 88→    getNextPageParam: lastPage => getNextCursor(lastPage),
 89→  });
 90→
 91→  const posts = useMemo(
 92→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
 93→    [feedQuery.data?.pages],
 94→  );
 95→
 96→  const onRefresh = async () => {
 97→    setRefreshing(true);
