    borderColor: colors.border,
    padding: 14,
    marginBottom: 10,
    gap: 6,
  },
  postCardPressed: {
    opacity: 0.85,
  },
  postTitle: {
    color: colors.text,
    fontSize: 17,
    fontWeight: '700',
  },
  postMeta: {
    color: colors.textMuted,
    fontSize: 13,
  },
  postBody: {
    color: colors.text,
    fontSize: 14,
    lineHeight: 20,
  },
  statsRow: {
    flexDirection: 'row',
    gap: 12,
    marginTop: 2,
  },
  statText: {
    color: colors.textMuted,
    fontSize: 12,
    fontWeight: '600',
  },
  emptyCard: {
    marginTop: 30,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: colors.border,
    backgroundColor: colors.surface,
    padding: 16,
    gap: 8,
  },
  emptyTitle: {
    color: colors.text,
    fontSize: 16,
    fontWeight: '700',
  },
  emptyText: {
    color: colors.textMuted,
    fontSize: 14,
  },
});

