import React from 'react';
import {
  FlatList,
  Image,
  Pressable,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import {useQuery} from '@tanstack/react-query';
import {useNavigation} from '@react-navigation/native';
import {NativeStackNavigationProp} from '@react-navigation/native-stack';
import {useTheme} from '../../theme/ThemeProvider';
import {fonts, typeScale} from '../../theme/typography';
import {spacing, radii, shadows} from '../../theme/spacing';
import {mobileApi, type JournalItem} from '../../lib/api/mobileApi';
import type {RootStackParamList} from '../../navigation/types';

interface RelatedPostsProps {
  journalId: string;
}

const extractImage = (content: string | null | undefined): string | null => {
  if (!content) return null;
  try {
    const parsed = JSON.parse(content);
    const find = (node: any): string | null => {
      if (node.type === 'image' && node.src) return node.src;
      if (node.children) {
        for (const child of node.children) {
          const found = find(child);
          if (found) return found;
        }
      }
      return null;
    };
    return find(parsed.root ?? parsed);
  } catch {
    return null;
  }
};

export function RelatedPosts({journalId}: RelatedPostsProps) {
  const {colors} = useTheme();
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();

  const {data, isLoading} = useQuery({
    queryKey: ['related-posts', journalId],
    queryFn: () => mobileApi.getRelatedPosts(journalId),
    enabled: Boolean(journalId),
  });

  const posts = data?.data ?? [];

  if (isLoading || posts.length < 2) return null;

  return (
    <View style={styles.container}>
      <Text style={[styles.title, {color: colors.textHeading}]}>
        Related Posts
      </Text>
      <FlatList
        horizontal
        data={posts}
        keyExtractor={item => item.id}
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.scrollContent}
        renderItem={({item}) => {
          const image = extractImage(item.content);
          return (
            <Pressable
              onPress={() =>
                navigation.push('PostDetail', {journalId: item.id})
              }
              style={[
                styles.card,
