 21→export function StoryDetailScreen({route, navigation}: Props) {
 22→  const {storyId} = route.params;
 23→  const {session} = useAuth();
 24→  const token = session?.access_token;
 25→  const queryClient = useQueryClient();
 26→
 27→  const storyQuery = useQuery({
 28→    queryKey: ['story', storyId, token],
 29→    queryFn: () => storyApi.getStoryById(storyId, token),
 30→  });
 31→
 32→  const voteMutation = useMutation({
 33→    mutationFn: () => storyApi.toggleVote(token ?? '', storyId),
 34→    onSuccess: () => queryClient.invalidateQueries({queryKey: ['story', storyId]}),
 35→  });
 36→
 37→  const libraryMutation = useMutation({
 38→    mutationFn: () => storyApi.toggleLibrary(token ?? '', storyId),
 39→    onSuccess: () => {
 40→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 41→      queryClient.invalidateQueries({queryKey: ['stories-library']});
 42→    },
 43→  });
 44→
 45→  const onToggleVote = () => {
 46→    if (!token) {
 47→      Alert.alert('Login required', 'Sign in to vote on stories.');
 48→      return;
 49→    }
 50→    voteMutation.mutate();
 51→  };
 52→
 53→  const onToggleLibrary = () => {
 54→    if (!token) {
 55→      Alert.alert('Login required', 'Sign in to save stories to library.');
 56→      return;
 57→    }
 58→    libraryMutation.mutate();
 59→  };
 60→
 61→  if (storyQuery.isLoading) {
 62→    return (
 63→      <Screen>
 64→        <View style={styles.loading}>
 65→          <ActivityIndicator color={colors.accent} />
 66→          <Text style={styles.meta}>Loading story...</Text>
 67→        </View>
 68→      </Screen>
 69→    );
 70→  }
 71→
 72→  if (!storyQuery.data) {
 73→    return (
 74→      <Screen>
 75→        <Text style={styles.error}>Story not found.</Text>
 76→      </Screen>
 77→    );
 78→  }
 79→
 80→  const story = storyQuery.data;
 81→  const chapters = story.chapters ?? [];
 82→
 83→  return (
 84→    <Screen>
 85→      <Text style={styles.title}>{story.title}</Text>
 86→      <Text style={styles.meta}>
 87→        {(story.users?.name || 'Unknown author') +
 88→          ` • ${(story.status || 'ongoing').toString()}`}
 89→      </Text>
 90→
 91→      {!!story.description && (
 92→        <View style={styles.card}>
 93→          <Text style={styles.cardTitle}>About</Text>
 94→          <Text style={styles.description}>{story.description}</Text>
 95→        </View>
 96→      )}
 97→
 98→      <View style={styles.actionRow}>
 99→        <PrimaryButton
100→          label={story.has_voted ? `Voted (${story.vote_count || 0})` : `Vote (${story.vote_count || 0})`}
101→          onPress={onToggleVote}
102→          kind={story.has_voted ? 'primary' : 'secondary'}
103→          loading={voteMutation.isPending}
104→        />
105→        <PrimaryButton
106→          label={story.in_library ? 'In Library' : 'Add Library'}
107→          onPress={onToggleLibrary}
108→          kind={story.in_library ? 'primary' : 'secondary'}
109→          loading={libraryMutation.isPending}
110→        />
111→      </View>
112→
113→      {token && (
114→        <View style={styles.actionRow}>
115→          <PrimaryButton
116→            label="Manage"
117→            onPress={() => navigation.navigate('StoryChapterManager', {storyId})}
118→            kind="secondary"
119→          />
120→          <PrimaryButton
121→            label="Edit Story"
122→            onPress={() => navigation.navigate('StoryEditor', {storyId})}
123→            kind="secondary"
124→          />
125→        </View>
126→      )}
127→
128→      <View style={styles.card}>
129→        <Text style={styles.cardTitle}>Chapters ({chapters.length})</Text>
130→        {chapters.length === 0 ? (
131→          <Text style={styles.meta}>No chapters available yet.</Text>
132→        ) : (
133→          chapters.map(chapter => (
134→            <Pressable
135→              key={chapter.id}
136→              onPress={() =>
137→                navigation.navigate('StoryChapterReader', {
138→                  storyId,
139→                  chapterId: chapter.id,
140→                })
141→              }
142→              style={({pressed}) => [styles.chapterItem, pressed && styles.chapterPressed]}>
143→              <Text style={styles.chapterTitle}>
144→                {`Ch. ${chapter.chapter_number || '?'}: ${chapter.title}`}
145→              </Text>
146→              <Text style={styles.chapterMeta}>
147→                {(chapter.status || 'draft').toString()}
148→                {` • ${(chapter.word_count || 0).toLocaleString()} words`}
149→              </Text>
150→            </Pressable>
151→          ))
152→        )}
153→      </View>
154→    </Screen>
155→  );
156→}
