 23→export function StoryChapterManagerScreen({route, navigation}: Props) {
 24→  const {storyId} = route.params;
 25→  const {session} = useAuth();
 26→  const token = session?.access_token ?? '';
 27→  const queryClient = useQueryClient();
 28→
 29→  const storyQuery = useQuery({
 30→    queryKey: ['story', storyId, token],
 31→    queryFn: () => storyApi.getStoryById(storyId, token),
 32→  });
 33→
 34→  const [newChapterTitle, setNewChapterTitle] = useState('');
 35→
 36→  const createMutation = useMutation({
 37→    mutationFn: () =>
 38→      storyApi.createChapter(
 39→        token,
 40→        storyId,
 41→        newChapterTitle.trim() || `Chapter ${(storyQuery.data?.chapters?.length || 0) + 1}`,
 42→      ),
 43→    onSuccess: data => {
 44→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 45→      setNewChapterTitle('');
 46→      navigation.navigate('StoryChapterEditor', {storyId, chapterId: data.id});
 47→    },
 48→    onError: error => {
 49→      Alert.alert(
 50→        'Create chapter failed',
 51→        error instanceof Error ? error.message : 'Unknown error',
 52→      );
 53→    },
 54→  });
 55→
 56→  const deleteMutation = useMutation({
 57→    mutationFn: (chapterId: string) => storyApi.deleteChapter(token, storyId, chapterId),
 58→    onSuccess: () => {
 59→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 60→    },
 61→  });
 62→
 63→  const publishMutation = useMutation({
 64→    mutationFn: (chapterId: string) =>
 65→      storyApi.updateChapter(token, storyId, chapterId, {status: 'published'}),
 66→    onSuccess: () => queryClient.invalidateQueries({queryKey: ['story', storyId]}),
 67→  });
 68→
 69→  const chapters = useMemo(
 70→    () =>
 71→      [...(storyQuery.data?.chapters ?? [])].sort(
 72→        (a, b) => (a.chapter_number || 0) - (b.chapter_number || 0),
 73→      ),
 74→    [storyQuery.data?.chapters],
 75→  );
 76→
 77→  const onDelete = (chapterId: string, title: string) => {
 78→    Alert.alert('Delete chapter', `Delete "${title}"?`, [
 79→      {text: 'Cancel', style: 'cancel'},
 80→      {text: 'Delete', style: 'destructive', onPress: () => deleteMutation.mutate(chapterId)},
 81→    ]);
 82→  };
 83→
 84→  if (storyQuery.isLoading) {
 85→    return (
 86→      <Screen>
 87→        <View style={styles.loading}>
 88→          <ActivityIndicator color={colors.accent} />
 89→          <Text style={styles.meta}>Loading story...</Text>
 90→        </View>
 91→      </Screen>
 92→    );
 93→  }
 94→
 95→  if (!storyQuery.data) {
 96→    return (
 97→      <Screen>
 98→        <Text style={styles.error}>Story not found.</Text>
 99→      </Screen>
100→    );
101→  }
102→
103→  return (
104→    <Screen scroll={false}>
105→      <ScrollView contentContainerStyle={styles.content}>
106→        <Text style={styles.title}>{storyQuery.data.title}</Text>
107→        <Text style={styles.meta}>{`${chapters.length} chapters`}</Text>
108→
109→        <View style={styles.card}>
110→          <Text style={styles.sectionTitle}>Create chapter</Text>
111→          <TextInput
112→            value={newChapterTitle}
113→            onChangeText={setNewChapterTitle}
114→            placeholder="Chapter title"
115→            placeholderTextColor={colors.textMuted}
116→            style={styles.input}
117→          />
118→          <PrimaryButton
119→            label="Create"
120→            onPress={() => createMutation.mutate()}
121→            loading={createMutation.isPending}
122→          />
123→        </View>
124→
125→        <View style={styles.card}>
126→          <Text style={styles.sectionTitle}>Manage chapters</Text>
127→          {chapters.length === 0 ? (
128→            <Text style={styles.meta}>No chapters yet.</Text>
129→          ) : (
130→            chapters.map(chapter => (
131→              <View key={chapter.id} style={styles.chapterRow}>
132→                <Pressable
133→                  onPress={() =>
134→                    navigation.navigate('StoryChapterReader', {
135→                      storyId,
136→                      chapterId: chapter.id,
137→                    })
138→                  }
139→                  style={({pressed}) => [styles.chapterTouch, pressed && styles.chapterPressed]}>
140→                  <Text style={styles.chapterTitle}>
141→                    {`Ch. ${chapter.chapter_number || '?'}: ${chapter.title}`}
142→                  </Text>
143→                  <Text style={styles.chapterMeta}>
144→                    {(chapter.status || 'draft').toString()}
145→                    {` • ${(chapter.word_count || 0).toLocaleString()} words`}
146→                  </Text>
147→                </Pressable>
148→                <View style={styles.actions}>
149→                  <PrimaryButton
150→                    label="Edit"
151→                    onPress={() =>
152→                      navigation.navigate('StoryChapterEditor', {
153→                        storyId,
154→                        chapterId: chapter.id,
155→                      })
156→                    }
157→                    kind="secondary"
158→                  />
159→                  <PrimaryButton
160→                    label="Publish"
161→                    onPress={() => publishMutation.mutate(chapter.id)}
162→                    kind="secondary"
163→                    loading={publishMutation.isPending}
164→                  />
165→                  <PrimaryButton
166→                    label="Delete"
167→                    onPress={() => onDelete(chapter.id, chapter.title)}
168→                    kind="danger"
169→                    loading={deleteMutation.isPending}
170→                  />
171→                </View>
172→              </View>
173→            ))
174→          )}
175→        </View>
176→      </ScrollView>
177→    </Screen>
