 28→export function StoryChapterEditorScreen({route, navigation}: Props) {
 29→  const {storyId, chapterId} = route.params;
 30→  const {session} = useAuth();
 31→  const token = session?.access_token ?? '';
 32→  const editorRef = useRef<RichEditor>(null);
 33→
 34→  const chapterQuery = useQuery({
 35→    queryKey: ['story-chapter', storyId, chapterId, token],
 36→    queryFn: () => storyApi.getChapter(storyId, chapterId, token),
 37→  });
 38→
 39→  const [chapterTitle, setChapterTitle] = useState('');
 40→  const [html, setHtml] = useState('');
 41→
 42→  useEffect(() => {
 43→    if (chapterQuery.data) {
 44→      setChapterTitle(chapterQuery.data.title || '');
 45→      const text = extractPlainTextFromLexical(chapterQuery.data.content);
 46→      setHtml(text);
 47→      editorRef.current?.setContentHTML(text);
 48→    }
 49→  }, [chapterQuery.data]);
 50→
 51→  const canSave = useMemo(
 52→    () => chapterTitle.trim().length > 0 && stripHtml(html).length > 0,
 53→    [chapterTitle, html],
 54→  );
 55→
 56→  const updateMutation = useMutation({
 57→    mutationFn: (status?: string) =>
 58→      storyApi.updateChapter(token, storyId, chapterId, {
 59→        title: chapterTitle.trim() || 'Untitled Chapter',
 60→        content: toLexicalFromPlainText(stripHtml(html)),
 61→        status,
 62→      }),
 63→    onSuccess: () => {
 64→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 65→      queryClient.invalidateQueries({queryKey: ['story-chapter', storyId, chapterId]});
 66→    },
 67→    onError: error => {
 68→      Alert.alert(
 69→        'Save failed',
 70→        error instanceof Error ? error.message : 'Unknown error',
 71→      );
 72→    },
 73→  });
 74→
 75→  const onSave = () => {
 76→    updateMutation.mutate(undefined, {
 77→      onSuccess: () => Alert.alert('Saved', 'Chapter saved.'),
 78→    });
 79→  };
 80→
 81→  const onPublish = () => {
 82→    updateMutation.mutate('published', {
 83→      onSuccess: () => {
 84→        Alert.alert('Published', 'Chapter published.');
 85→        navigation.goBack();
 86→      },
 87→    });
 88→  };
 89→
 90→  return (
 91→    <Screen>
 92→      <Text style={styles.title}>Edit Chapter</Text>
 93→      <TextInput
 94→        value={chapterTitle}
 95→        onChangeText={setChapterTitle}
 96→        placeholder="Chapter title"
 97→        placeholderTextColor={colors.textMuted}
 98→        style={styles.input}
 99→      />
100→
101→      <RichEditor
102→        ref={editorRef}
103→        style={styles.editor}
104→        placeholder="Start writing your chapter..."
105→        initialHeight={260}
106→        onChange={setHtml}
107→        editorStyle={richEditorStyle}
108→      />
109→      <RichToolbar
110→        editor={editorRef}
111→        actions={[
112→          actions.setBold,
113→          actions.setItalic,
114→          actions.setUnderline,
115→          actions.insertBulletsList,
116→          actions.insertOrderedList,
117→        ]}
118→        selectedIconTint={colors.accent}
119→        iconTint={colors.textMuted}
120→        style={styles.toolbar}
121→      />
122→
123→      <PrimaryButton
124→        label="Save Draft"
125→        onPress={onSave}
126→        loading={updateMutation.isPending}
127→        disabled={!canSave}
128→      />
129→      <PrimaryButton
130→        label="Publish"
131→        onPress={onPublish}
132→        kind="secondary"
133→        loading={updateMutation.isPending}
134→        disabled={!canSave}
135→      />
136→    </Screen>
137→  );
138→}
