import React from 'react';
import {
  ActivityIndicator,
  Alert,
  Pressable,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import {useMutation, useQuery, useQueryClient} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {Screen} from '../../components/Screen';
import {PrimaryButton} from '../../components/PrimaryButton';
import {storyApi} from '../../lib/api/storyApi';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'StoryDetail'>;

export function StoryDetailScreen({route, navigation}: Props) {
  const {colors} = useTheme();
  const {storyId} = route.params;
  const {session} = useAuth();
  const token = session?.access_token;
  const queryClient = useQueryClient();

  const storyQuery = useQuery({
    queryKey: ['story', storyId, token],
    queryFn: () => storyApi.getStoryById(storyId, token),
  });

  const voteMutation = useMutation({
    mutationFn: () => storyApi.toggleVote(token ?? '', storyId),
    onSuccess: () => queryClient.invalidateQueries({queryKey: ['story', storyId]}),
  });

  const libraryMutation = useMutation({
    mutationFn: () => storyApi.toggleLibrary(token ?? '', storyId),
    onSuccess: () => {
      queryClient.invalidateQueries({queryKey: ['story', storyId]});
      queryClient.invalidateQueries({queryKey: ['stories-library']});
    },
  });

  const onToggleVote = () => {
    if (!token) {
      Alert.alert('Login required', 'Sign in to vote on stories.');
      return;
    }
    voteMutation.mutate();
  };

  const onToggleLibrary = () => {
    if (!token) {
      Alert.alert('Login required', 'Sign in to save stories to library.');
      return;
    }
    libraryMutation.mutate();
  };

  if (storyQuery.isLoading) {
    return (
      <Screen>
        <View style={styles.loading}>
          <ActivityIndicator color={colors.accentAmber} />
          <Text style={[styles.meta, {color: colors.textMuted}]}>Loading story...</Text>
        </View>
      </Screen>
    );
  }

  if (!storyQuery.data) {
    return (
      <Screen>
        <Text style={[styles.error, {color: colors.danger}]}>Story not found.</Text>
      </Screen>
    );
  }

  const story = storyQuery.data;
  const chapters = story.chapters ?? [];

  return (
    <Screen>
      <Text style={[styles.title, {color: colors.textPrimary}]}>{story.title}</Text>
      <Text style={[styles.meta, {color: colors.textMuted}]}>
        {(story.users?.name || 'Unknown author') +
          ` • ${(story.status || 'ongoing').toString()}`}
      </Text>

      {!!story.description && (
        <View
          style={[
            styles.card,
            {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
          ]}>
          <Text style={[styles.cardTitle, {color: colors.textPrimary}]}>About</Text>
          <Text style={[styles.description, {color: colors.textPrimary}]}>{story.description}</Text>
        </View>
      )}

      <View style={styles.actionRow}>
        <PrimaryButton
          label={story.has_voted ? `Voted (${story.vote_count || 0})` : `Vote (${story.vote_count || 0})`}
          onPress={onToggleVote}
          kind={story.has_voted ? 'primary' : 'secondary'}
          loading={voteMutation.isPending}
        />
        <PrimaryButton
          label={story.in_library ? 'In Library' : 'Add Library'}
          onPress={onToggleLibrary}
          kind={story.in_library ? 'primary' : 'secondary'}
          loading={libraryMutation.isPending}
        />
      </View>

      {token && (
        <View style={styles.actionRow}>
          <PrimaryButton
            label="Manage"
            onPress={() => navigation.navigate('StoryChapterManager', {storyId})}
            kind="secondary"
          />
          <PrimaryButton
            label="Edit Story"
            onPress={() => navigation.navigate('StoryEditor', {storyId})}
            kind="secondary"
          />
        </View>
      )}

      <View
        style={[
          styles.card,
          {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
        ]}>
        <Text style={[styles.cardTitle, {color: colors.textPrimary}]}>Chapters ({chapters.length})</Text>
        {chapters.length === 0 ? (
          <Text style={[styles.meta, {color: colors.textMuted}]}>No chapters available yet.</Text>
        ) : (
          chapters.map(chapter => (
            <Pressable
              key={chapter.id}
              onPress={() =>
                navigation.navigate('StoryChapterReader', {
                  storyId,
                  chapterId: chapter.id,
                })
              }
              style={({pressed}) => [
                styles.chapterItem,
                {borderTopColor: colors.borderLight},
                pressed && styles.chapterPressed,
              ]}>
              <Text style={[styles.chapterTitle, {color: colors.textPrimary}]}>
                {`Ch. ${chapter.chapter_number || '?'}: ${chapter.title}`}
              </Text>
              <Text style={[styles.chapterMeta, {color: colors.textMuted}]}>
                {(chapter.status || 'draft').toString()}
                {` • ${(chapter.word_count || 0).toLocaleString()} words`}
              </Text>
            </Pressable>
          ))
        )}
      </View>
    </Screen>
  );
}

const styles = StyleSheet.create({
  loading: {
